import React from 'react';
import { Disclosure as CarbonDisclosure } from '@carbon/react';

const Disclosure = (props) => {
    const {
        id,
        setProps,
        children,
        className,
        ...otherProps
    } = props;

    return (
        <CarbonDisclosure
            id={id}
            className={className}
            {...otherProps}
        >
            {children}
        </CarbonDisclosure>
    );
};

Disclosure.defaultProps = {
    className: ''
};

export default Disclosure;
